import { inject } from '@angular/core';
import {
  Observable,
  throwError,
  switchMap,
  filter,
  take,
  retry,
  timer,
  catchError,
  timeout,
  TimeoutError,
} from 'rxjs';
import { AuthService } from '../services/auth.service';
import { AuthTokenManagerService } from '../services/auth-token-manager.service';
import { ApiErrorResponse } from '../models/auth.model';
import { ErrorReasons } from '../models/error-reasons.enum';
import { ToastService } from '../services/toast.service';
import { AuthDataService } from '../services/auth-data.service';
import { isDefined } from '../../shared/utils';
import {
  HttpRequest,
  HttpHandlerFn,
  HttpEvent,
  HttpErrorResponse,
  HttpInterceptorFn,
} from '@angular/common/http';
import { UserSessionResponse } from '../../api';
import { TokenRefreshCoordinatorService } from '../services/token-refresh-coordinator.service';

const TOKEN_REFRESH_TIMEOUT_MS = 10000; // 10 seconds timeout for token refresh
let last401ToastTime = 0;
const TOAST_THROTTLE_MS = 3000;

function shouldRetryError(error: HttpErrorResponse): boolean {
  if (!navigator.onLine) {
    return false;
  }
  const retryableStatuses = [0, 408, 500, 502, 503, 504];
  return retryableStatuses.includes(error.status);
}

function createErrorObject(
  error: HttpErrorResponse,
  req: HttpRequest<unknown>,
): ApiErrorResponse {
  if (!navigator.onLine) {
    return {
      errorReason: ErrorReasons.NetworkError,
      errorMessage:
        'No internet connection. Please check your network and try again.',
      token: null,
      valid: false,
    };
  }
  switch (error.status) {
    case 401:
      return {
        errorReason: ErrorReasons.Unauthorized,
        errorMessage: req.url.includes('/auth/signin')
          ? 'Invalid username or password.'
          : 'Your session has expired. Please log in again.',
        token: null,
        valid: false,
      };
    case 403:
      return {
        errorReason: ErrorReasons.Forbidden,
        errorMessage: 'You do not have permission to perform this action.',
        token: null,
        valid: false,
      };
    case 404:
      return {
        errorReason: ErrorReasons.InvalidEndpoint,
        errorMessage: 'The requested resource was not found',
        token: null,
        valid: false,
      };
    case 408:
    case 504:
      return {
        errorReason: ErrorReasons.RequestTimeout,
        errorMessage: 'The request timed out. Please try again',
        token: null,
        valid: false,
      };
    case 429:
      return {
        errorReason: ErrorReasons.TooManyLogins,
        errorMessage: 'Too many login attempts. Please try again later',
        token: null,
        valid: false,
      };
    case 500:
    case 502:
    case 503:
      return {
        errorReason: ErrorReasons.ServerError,
        errorMessage: 'Server is currently unavailable. Please try again later',
        token: null,
        valid: false,
      };
    case 400: {
      let detailedMessage = error.error.message ?? 'Bad request';
      if (isDefined(error.error?.data?.fields)) {
        const fieldErrors = Object.values(error.error.data.fields)
          .map((field) => (field as { message: string }).message)
          .filter(Boolean)
          .join('. ');
        if (fieldErrors) {
          detailedMessage += `: ${fieldErrors}`;
        }
      }
      return {
        errorReason: ErrorReasons.BadRequest,
        errorMessage: detailedMessage,
        token: null,
        valid: false,
      };
    }
    default:
      return {
        errorReason: ErrorReasons.Unknown,
        errorMessage: 'An unexpected error occurred. Please try again',
        token: null,
        valid: false,
      };
  }
}

export const AuthInterceptor: HttpInterceptorFn = (req, next) => {
  const toastService = inject(ToastService);
  const authService = inject(AuthService);
  const authTokenManagerService = inject(AuthTokenManagerService);
  const authDataService = inject(AuthDataService);
  const tokenRefreshCoordinator = inject(TokenRefreshCoordinatorService);

  function addToken(
    req: HttpRequest<unknown>,
    token: string,
  ): HttpRequest<unknown> {
    return req.clone({
      setHeaders: {
        'x-access-token': `${token}`,
      },
    });
  }

  function showToastForError(errorObject: ApiErrorResponse): void {
    switch (errorObject.errorReason) {
      case ErrorReasons.Unauthorized: {
        const now = Date.now();
        if (now - last401ToastTime > TOAST_THROTTLE_MS) {
          toastService.showError('Unauthorized', errorObject.errorMessage);
          last401ToastTime = now;
        }
        break;
      }
      case ErrorReasons.NetworkError:
        toastService.showError('Network Error', errorObject.errorMessage);
        break;
      case ErrorReasons.ServerError:
        toastService.showError('Server Error', errorObject.errorMessage);
        break;
      case ErrorReasons.InvalidEndpoint:
        toastService.showError('Service Unavailable', errorObject.errorMessage);
        break;
      case ErrorReasons.RequestTimeout:
        toastService.showError('Request Timeout', errorObject.errorMessage);
        break;
      case ErrorReasons.TooManyLogins:
        toastService.showError('Too Many Logins', errorObject.errorMessage);
        break;
      case ErrorReasons.BadRequest:
        toastService.showError('Validation Error', errorObject.errorMessage);
        break;
      case ErrorReasons.Unknown:
        toastService.showError('Error', errorObject.errorMessage);
        break;
      case ErrorReasons.Forbidden:
        toastService.showError('Forbidden', errorObject.errorMessage);
        break;
    }
  }

  function handle401Error(
    req: HttpRequest<unknown>,
    next: HttpHandlerFn,
    refreshToken: string,
  ): Observable<HttpEvent<unknown>> {
    if (req.url.includes('/auth/refresh')) {
      authDataService.forceLogout();
      return throwError(
        () => new Error('Refresh token request failed. Logging out.'),
      );
    }

    // First request to hit 401 initiates the refresh
    if (tokenRefreshCoordinator.refreshTokenInProgress === false) {
      tokenRefreshCoordinator.startRefresh();

      return authService.refreshToken(refreshToken).pipe(
        timeout(TOKEN_REFRESH_TIMEOUT_MS),
        switchMap((authResponse: UserSessionResponse) => {
          // Success: store tokens and notify all waiting requests
          authTokenManagerService.storeTokens(authResponse);
          tokenRefreshCoordinator.notifyRefreshSuccess(
            authResponse.accessToken,
          );
          tokenRefreshCoordinator.resetRefreshState();
          return next(addToken(req, authResponse.accessToken));
        }),
        catchError((error) => {
          // Failure: notify all waiting requests and force logout
          const errorMessage =
            error instanceof TimeoutError
              ? 'Token refresh timed out'
              : `Token refresh error: ${error.message}`;

          const refreshError = new Error(errorMessage);
          tokenRefreshCoordinator.notifyRefreshError(refreshError);
          tokenRefreshCoordinator.resetRefreshState();
          authDataService.forceLogout();

          return throwError(() => refreshError);
        }),
      );
    } else {
      // Subsequent requests wait for the refresh to complete
      return tokenRefreshCoordinator.refreshTokenSubject.pipe(
        filter(
          (state) => state.status === 'success' || state.status === 'error',
        ),
        take(1),
        timeout({
          each: TOKEN_REFRESH_TIMEOUT_MS,
          with: () =>
            throwError(
              () =>
                new Error(
                  'Timeout waiting for token refresh. Please try again.',
                ),
            ),
        }),
        switchMap((state) => {
          if (state.status === 'success') {
            // Refresh succeeded, retry the request with new token
            return next(addToken(req, state.token));
          } else {
            // Refresh failed, propagate the error
            return throwError(() => state.error);
          }
        }),
        catchError((error) => {
          // Handle timeout or other errors from waiting
          if (
            error instanceof Error &&
            error.message?.includes('Timeout waiting for token refresh')
          ) {
            authDataService.forceLogout();
          }
          return throwError(() => error);
        }),
      );
    }
  }

  function handleError(
    req: HttpRequest<unknown>,
    next: HttpHandlerFn,
    error: HttpErrorResponse,
  ): Observable<HttpEvent<unknown>> {
    // Silent 404s for avatar endpoints - these are expected when no avatar exists
    if (
      error.status === 404 &&
      req.url.includes('/entities/assets/') &&
      req.url.includes('/avatar')
    ) {
      return throwError(() => error);
    }

    const errorObject = createErrorObject(error, req);
    if (error.status === 401) {
      // Prevent infinite loop: do not refresh for signin or refresh endpoints
      if (
        req.url.includes('/auth/signin') ||
        req.url.includes('/auth/refresh')
      ) {
        showToastForError(errorObject);
        return throwError(() => errorObject);
      }
      const refreshToken = authTokenManagerService.getRefreshToken();
      return isDefined(refreshToken)
        ? handle401Error(req, next, refreshToken).pipe(
            catchError((refreshError) => {
              authDataService.forceLogout();
              showToastForError(errorObject);
              return throwError(() => refreshError);
            }),
          )
        : (() => {
            authDataService.forceLogout();
            showToastForError(errorObject);
            return throwError(() => errorObject);
          })();
    }
    showToastForError(errorObject);
    return throwError(() => new Error(errorObject.errorMessage));
  }

  // Check if this is an external API call (Telemetry API or Cloudflare Workers)
  const isExternalApi =
    req.url.includes('kt1.io') ||
    req.url.includes('api.us1.kt1.io') ||
    req.url.includes('workers.dev'); // Cloudflare Worker backend

  let request: HttpRequest<unknown> = req;

  // Only add CypherView token for internal API calls
  if (!isExternalApi) {
    const accessToken = authTokenManagerService.getAccessToken();
    if (isDefined(accessToken)) {
      request = addToken(req, accessToken);
    }
  }

  // Skip error handling for external APIs
  if (isExternalApi) {
    return next(request);
  }

  return next(request).pipe(
    retry({
      count: 1,
      delay: (error: HttpErrorResponse, retryCount: number) => {
        if (shouldRetryError(error)) {
          return timer(1000 * Math.pow(2, retryCount - 1));
        }
        throw error;
      },
    }),
    catchError((error) => handleError(request, next, error)),
  );
};
