import { Injectable, signal } from '@angular/core';

@Injectable({
  providedIn: 'root',
})
export class LayoutService {
  readonly sidebarVisible = signal<boolean>(true);
  readonly fontFamily = signal<string>('Ubuntu, sans-serif');

  toggleSidebar(visible?: boolean): void {
    visible = visible ?? !this.sidebarVisible();
    this.sidebarVisible.set(visible);
  }

  setFontFamily(fontFamily: string): void {
    this.fontFamily.set(fontFamily);
    this.updateFontFamily(fontFamily);
  }

  private updateFontFamily(fontFamily: string): void {
    const fontUrl = `https://fonts.googleapis.com/css2?family=${fontFamily.replace(' ', '+')}:wght@400;500;700&display=swap`;

    // Preload the font
    const preloadLink = document.createElement('link');
    preloadLink.href = fontUrl;
    preloadLink.rel = 'preload';
    preloadLink.as = 'style';
    document.head.appendChild(preloadLink);

    // Check if the font is already loaded
    if (!document.querySelector(`link[href="${fontUrl}"]`)) {
      // Append the actual stylesheet link after preloading
      const stylesheetLink = document.createElement('link');
      stylesheetLink.href = fontUrl;
      stylesheetLink.rel = 'stylesheet';
      document.head.appendChild(stylesheetLink);
    }

    // Apply the font family to the document
    document.documentElement.style.setProperty('--font-family', fontFamily);
  }
}
