import {
  Component,
  DestroyRef,
  inject,
  OnInit,
  OnDestroy,
  signal,
} from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { filter } from 'rxjs';
import {
  ActivatedRoute,
  NavigationEnd,
  Router,
  RouterModule,
} from '@angular/router';
import { SplitterModule } from 'primeng/splitter';
import { ScrollPanelModule } from 'primeng/scrollpanel';
import { MessageService } from 'primeng/api';

import { SidebarComponent } from '../sidebar/sidebar.component';
import { AuthDataService } from '../../../core/services/auth-data.service';
import { ThemeComponent } from '../../../shared/components/theme/theme.component';
import { UserProfileResponse } from '../../../api';
import { FlutterLayoutComponent } from '../flutter-layout/flutter-layout.component';
import { ProgressSpinnerModule } from 'primeng/progressspinner';
import { CommonModule } from '@angular/common';
import { ActionType } from '../../../core/models/message.model';
import { BroadcastMessageService } from '../../../core/services/message.service';
import { MeasurementDateTimeService } from '../../../shared/services/measurement-units/measurement-date-time.service';

@Component({
  selector: 'app-main-layout',
  imports: [
    RouterModule,
    SplitterModule,
    SidebarComponent,
    ScrollPanelModule,
    ThemeComponent,
    FlutterLayoutComponent,
    ProgressSpinnerModule,
    CommonModule,
  ],
  templateUrl: './main-layout.component.html',
  styleUrls: ['./main-layout.component.scss'],
})
export class MainLayoutComponent implements OnInit, OnDestroy {
  private readonly authDataService = inject(AuthDataService);
  private readonly messageService = inject(MessageService);
  private readonly destroyRef = inject(DestroyRef);
  private readonly router = inject(Router);
  private readonly activatedRoute = inject(ActivatedRoute);
  private readonly broadcastService = inject(BroadcastMessageService);
  private readonly measurementDateTimeService = inject(
    MeasurementDateTimeService,
  );
  readonly isFlutterRoute = signal(false);
  readonly isIframeRoute = signal(false);
  readonly iframeUrl = signal<string | null>(null);

  constructor() {}

  ngOnInit(): void {
    this.initializeUserAndClient();
    this.setupViewportHeight();
    this.checkRouteData();

    this.router.events
      .pipe(
        filter(
          (event): event is NavigationEnd => event instanceof NavigationEnd,
        ),
        takeUntilDestroyed(this.destroyRef),
      )
      .subscribe(() => {
        const isFlutterRoute = this.checkRouteData();

        if (isFlutterRoute) {
          this.handleFlutterNavigation();
        }
      });
  }

  private handleFlutterNavigation(): void {
    const fullRoute = this.router.url;
    const [path, queryString] = fullRoute.split('?');
    const cleanPath = path.replaceAll(/(^\/+)|(\/+$)/g, '');
    const flutterRoute = this.broadcastService.getFlutterRoute(cleanPath);
    const queryParams = queryString
      ? Object.fromEntries(new URLSearchParams(queryString))
      : undefined;

    this.broadcastService.sendAction(ActionType.navigate, {
      route: flutterRoute,
      queryParams,
      timestamp: Date.now(),
    });
  }

  private checkRouteData(): boolean {
    let route = this.activatedRoute;
    while (route.firstChild) {
      route = route.firstChild;
    }

    const routeData = route.snapshot.data;
    const isFlutterRoute = routeData['isFlutterRoute'] ?? false;
    const isIframeRoute = routeData['isIframeRoute'] ?? false;
    const iframeUrl = routeData['iframeUrl'] ?? null;

    this.isFlutterRoute.set(isFlutterRoute);
    this.isIframeRoute.set(isIframeRoute);
    this.iframeUrl.set(iframeUrl);

    return isFlutterRoute;
  }

  private initializeUserAndClient() {
    this.activatedRoute.data
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe({
        next: (data) => {
          const userProfile: UserProfileResponse = data['userProfile'];
          void this.authDataService.setUserProfile(userProfile);
          this.measurementDateTimeService.setTimezoneId(
            userProfile.timeZoneId ?? 'UTC',
          );
        },
        error: () => {
          this.messageService.add({
            severity: 'error',
            summary: 'Error',
            detail: 'Failed to load user profile',
          });
        },
      });
  }

  private setupViewportHeight(): void {
    const setViewportHeight = () => {
      const vh = window.innerHeight * 0.01;
      document.documentElement.style.setProperty('--vh', `${vh}px`);
    };
    const handleOrientationChange = () => {
      setTimeout(setViewportHeight, 100);
    };
    setViewportHeight();
    window.addEventListener('resize', setViewportHeight);
    window.addEventListener('orientationchange', handleOrientationChange);

    this.destroyRef.onDestroy(() => {
      window.removeEventListener('resize', setViewportHeight);
      window.removeEventListener('orientationchange', handleOrientationChange);
    });
  }

  ngOnDestroy(): void {
    this.authDataService.clearAllUserData();
  }
}
